<script setup lang="ts">
import { computed, ref } from 'vue'
import { onPullDownRefresh, onShow } from '@dcloudio/uni-app'
import {
  approveMobilePurchaseOrder, cancelMobileWarehouseTransfer, createMobilePurchaseOrder, createMobileWarehouseTransfer,
  getMobileWarehouseOverview, getMobileWarehouses, getMobileWarehouseTransferContext,
  getMobileWarehouseTransfers, receiveMobilePurchaseOrder, receiveMobileWarehouseTransfer,
  reviewMobileWarehouseTransfer, shipMobileWarehouseTransfer, submitMobileWarehouseTransfer,
  updateMobileWarehouseAlert, deleteMobileWarehouseItemCategory, getMobileWarehouseItemCategories, receiveMobileWarehouseStock,
  getMobileWarehouseItems, saveMobileWarehouseItem, saveMobileWarehouseItemCategory,
  setMobileWarehouseItemCategoryEnabled, setMobileWarehouseItemEnabled,
} from '@/api/business'
import { canPerformMobileAction, hasPermission } from '@/permissions'
import { openProtectedFile, showOperationFailure } from '@/platform'
import { useSessionStore } from '@/stores'
import type { WarehouseFacility, WarehouseItem, WarehouseItemCategory, WarehouseOverview, WarehousePurchaseOrder, WarehouseTransfer, WarehouseTransferContext } from '@/types/business'

const session=useSessionStore(),facilities=ref<WarehouseFacility[]>([]),warehouseIndex=ref(0),overview=ref<WarehouseOverview|null>(null),transfers=ref<WarehouseTransfer[]>([]),context=ref<WarehouseTransferContext|null>(null),catalogItems=ref<WarehouseItem[]>([]),categories=ref<WarehouseItemCategory[]>([])
const tab=ref<'purchase'|'transfer'|'inventory'|'movement'|'catalog'>('purchase'),loading=ref(false),acting=ref(''),message=ref('')
const supplierIndex=ref(0),purchaseFormOpen=ref(false),purchaseLines=ref<Array<{itemIndex:number;quantity:string;unitCost:string}>>([{itemIndex:0,quantity:'',unitCost:''}]),purchaseNote=ref(''),routeIndex=ref(-1),transferLines=ref<Array<{itemIndex:number;quantity:string;note:string}>>([{itemIndex:0,quantity:'',note:''}]),transferNote=ref('')
const categoryIndex=ref(0),itemFormOpen=ref(false),editingItemId=ref<number|undefined>(),newItemCode=ref(''),newItemName=ref(''),newItemUnit=ref(''),newPurchaseUnit=ref(''),newIngredientUnit=ref(''),newConversion=ref(''),newItemSpec=ref(''),newItemLocation=ref(''),newItemMinStock=ref(''),newItemPrice=ref(''),newShelfLife=ref(''),newExpiryAlertDays=ref(''),newItemAttributes=ref(''),newItemDescription=ref(''),newItemImageUrl=ref('')
const stockItemIndex=ref(0),stockBatchNo=ref(''),stockReceivedDate=ref(today()),stockExpiryDate=ref(''),stockQuantity=ref(''),stockUnitCost=ref(''),stockNote=ref('')
const receiveDrafts=ref<Record<string,string>>({})
const purchaseReceiveDrafts=ref<Record<string,{batchNo:string;receivedDate:string;expiryDate:string;note:string}>>({})
const inventoryFilter=ref<'RISK'|'OUT'|'LOW'|'EXPIRING'|'OVERSTOCK'|'OK'|'ALL'>('RISK')
const movementDirection=ref<'ALL'|'IN'|'OUT'>('ALL'),movementKeyword=ref(''),movementDateFrom=ref(''),movementDateTo=ref('')
const tabs=[{k:'purchase',l:'采购入库'},{k:'transfer',l:'仓间调拨'},{k:'inventory',l:'库存预警'},{k:'movement',l:'出入库记录'},{k:'catalog',l:'物料档案'}] as const
const currentWarehouse=computed(()=>facilities.value[warehouseIndex.value]||null),suppliers=computed(()=>overview.value?.suppliers?.filter(s=>s.active)||[]),items=computed(()=>overview.value?.items.filter(i=>i.active)||[]),routes=computed(()=>context.value?.routes.filter(route=>route.actions.canCreate)||[]),availableRoutes=computed(()=>routes.value),selectedRoute=computed(()=>availableRoutes.value[routeIndex.value]||null),routeMaterials=computed(()=>{const contextMaterials=selectedRoute.value?.materials||[];if(contextMaterials.length)return contextMaterials;const fallbackItems=items.value.length?items.value:catalogItems.value.filter(item=>item.active);return fallbackItems.map(item=>({itemId:item.id,itemName:item.name,unit:item.stockUnit||item.unit||'',availableQuantity:item.warehouseAvailableQuantity||0}))}),routeMaterialLabels=computed(()=>routeMaterials.value.map(material=>`${material.itemName||'未命名物料'} · 可调 ${quantity(material.availableQuantity)} ${material.unit||''}`)),warehouseNetwork=computed(()=>facilities.value.map(row=>({facility:row,summary:row.id===currentWarehouse.value?.id?overview.value?.summary:null})))
const flatCategories=computed(()=>flattenCategories(categories.value)),categoryNames=computed(()=>flatCategories.value.map(row=>row.name)),selectedCategory=computed(()=>flatCategories.value[categoryIndex.value]||null)
const inventoryItems=computed(()=>{const severity:Record<string,number>={OUT:0,EXPIRING:1,LOW:2,OVERSTOCK:3,OK:4};return(overview.value?.items||[]).filter(item=>inventoryFilter.value==='ALL'||inventoryFilter.value==='RISK'?item.alertLevel!=='OK':item.alertLevel===inventoryFilter.value).slice().sort((left,right)=>(severity[left.alertLevel]??9)-(severity[right.alertLevel]??9)||Number(left.daysAvailable??Infinity)-Number(right.daysAvailable??Infinity))})
const inventoryCounts=computed(()=>{const rows=overview.value?.items||[];return{risk:rows.filter(item=>item.alertLevel!=='OK').length,out:rows.filter(item=>item.alertLevel==='OUT').length,low:rows.filter(item=>item.alertLevel==='LOW').length,expiring:rows.filter(item=>item.alertLevel==='EXPIRING').length,overstock:rows.filter(item=>item.alertLevel==='OVERSTOCK').length}})
const filteredMovements=computed(()=>{const keyword=movementKeyword.value.trim().toLowerCase();return(overview.value?.movements||[]).filter(row=>{const date=String(row.createdAt||'').slice(0,10),isIn=Number(row.quantityDelta)>0;if(movementDirection.value==='IN'&&!isIn)return false;if(movementDirection.value==='OUT'&&isIn)return false;if(movementDateFrom.value&&date&&date<movementDateFrom.value)return false;if(movementDateTo.value&&date&&date>movementDateTo.value)return false;return !keyword||[row.itemName,row.movementTypeLabel,row.sourceType,row.sourceId,row.batchNo].some(value=>String(value||'').toLowerCase().includes(keyword))})})
const canPurchase=computed(()=>canPerformMobileAction(session.user,'warehouse.purchase')),canRequestTransfer=computed(()=>canPerformMobileAction(session.user,'warehouse.transfer.request')),canApproveTransfer=computed(()=>canPerformMobileAction(session.user,'warehouse.transfer.approve')),canShipTransfer=computed(()=>canPerformMobileAction(session.user,'warehouse.transfer.ship')),canReceiveTransfer=computed(()=>canPerformMobileAction(session.user,'warehouse.transfer.receive')),canConfigure=computed(()=>canPerformMobileAction(session.user,'warehouse.alert.configure')),canReadFiles=computed(()=>hasPermission(session.user,'attachment.read'))
onShow(load);onPullDownRefresh(async()=>{await refresh();uni.stopPullDownRefresh()})
async function load(){try{facilities.value=await getMobileWarehouses();await refresh()}catch(e){message.value=error(e)}}
async function refresh(){const warehouse=currentWarehouse.value;if(!warehouse||loading.value)return;loading.value=true;message.value='';try{const [nextOverview,nextTransfers,nextContext,nextItems,nextCategories]=await Promise.all([getMobileWarehouseOverview(warehouse.id),getMobileWarehouseTransfers(warehouse.id),getMobileWarehouseTransferContext(warehouse.id),getMobileWarehouseItems(),getMobileWarehouseItemCategories()]);overview.value={...nextOverview,purchaseOrders:(nextOverview.purchaseOrders||[]).filter(order=>order.status!=='RECEIVED')};transfers.value=nextTransfers;context.value=nextContext;catalogItems.value=nextItems;categories.value=nextCategories;if(!availableRoutes.value.length)routeIndex.value=-1;else if(routeIndex.value<0||routeIndex.value>=availableRoutes.value.length)routeIndex.value=0;for(const row of transfers.value)for(const line of row.lines){const draftKey=transferLineKey(row.id,line.itemId);if(receiveDrafts.value[draftKey]===undefined&&Number(line.inTransitQuantity)>0)receiveDrafts.value[draftKey]=String(line.inTransitQuantity)}for(const order of overview.value.purchaseOrders||[])for(const line of order.lines)purchaseDraft(order.id,line.itemId)}catch(e){message.value=error(e)}finally{loading.value=false}}
async function chooseWarehouse(e:{detail:{value:string|number}}){warehouseIndex.value=Number(e.detail.value);routeIndex.value=-1;await refresh()}
async function createPurchase(){const w=currentWarehouse.value,s=suppliers.value[supplierIndex.value],lines=purchaseLines.value.map(line=>{const item=items.value[line.itemIndex];return{itemId:item?.id||0,orderedQuantity:Number(line.quantity),unitCost:Number(line.unitCost)}});if(!canPurchase.value||!w||!s||!lines.length||lines.some(line=>line.itemId<=0||line.orderedQuantity<=0||line.unitCost<0)||new Set(lines.map(line=>line.itemId)).size!==lines.length){const content='请选择供应商；每项物料只可出现一次，并填写有效数量和单价。';message.value=content;showOperationFailure('操作失败',new Error(content));return}acting.value='purchase-create';try{await createMobilePurchaseOrder({warehouseId:w.id,supplierId:s.id,note:purchaseNote.value.trim()||undefined,clientRequestId:key('purchase'),lines});purchaseLines.value=[{itemIndex:0,quantity:'',unitCost:''}];purchaseNote.value='';purchaseFormOpen.value=false;await refresh();uni.showModal({title:'采购单已创建',content:'采购单已保存为草稿，请在下方确认采购后再办理入库。',showCancel:false})}catch(e){message.value=error(e)}finally{acting.value=''}}
async function approvePurchase(order:WarehousePurchaseOrder){if(!canPurchase.value)return;await work(order.id,()=>approveMobilePurchaseOrder(order.id),'采购单已确认')}
async function receivePurchase(order:WarehousePurchaseOrder){if(!canPurchase.value)return;const lines=order.lines.map(line=>{const draft=purchaseDraft(order.id,line.itemId);return{itemId:line.itemId,batchNo:draft.batchNo.trim(),receivedDate:draft.receivedDate,expiryDate:draft.expiryDate||undefined,quantity:Number(line.orderedQuantity),note:draft.note.trim()||undefined}});if(!lines.length||lines.some(line=>!line.batchNo||!line.receivedDate)){const content='请为每个采购物料填写批次号和到货日期。';message.value=content;showOperationFailure('操作失败',new Error(content));return}if(lines.some(line=>line.expiryDate&&line.expiryDate<line.receivedDate)){const content='到期日期不能早于到货日期。';message.value=content;showOperationFailure('操作失败',new Error(content));return}await work(order.id,()=>receiveMobilePurchaseOrder(order.id,{clientRequestId:key('purchase-receive'),lines}),'采购入库已完成')}
function addPurchaseLine(){purchaseLines.value.push({itemIndex:0,quantity:'',unitCost:''})}function removePurchaseLine(index:number){if(purchaseLines.value.length===1){message.value='采购单至少保留一条物料明细。';return}purchaseLines.value.splice(index,1)}
async function createTransfer(submit=false){const route=selectedRoute.value,lines=transferLines.value.map(line=>{const material=routeMaterials.value[line.itemIndex];return{itemId:material?.itemId||0,quantity:Number(line.quantity),note:line.note.trim()||undefined}});if(!canRequestTransfer.value||!route||!lines.length||lines.some(line=>line.itemId<=0||line.quantity<=0)||new Set(lines.map(line=>line.itemId)).size!==lines.length){const content='请选择可用调拨路线；每项物料只可出现一次，并填写有效数量。';message.value=content;uni.showModal({title:'无法保存调拨单',content,showCancel:false});return}acting.value='transfer-create';try{const created=await createMobileWarehouseTransfer({sourceWarehouseId:route.sourceWarehouse.id,targetWarehouseId:route.targetWarehouse.id,clientRequestId:key('transfer'),note:transferNote.value.trim()||undefined,lines});if(submit)await submitMobileWarehouseTransfer(created.id);transferLines.value=[{itemIndex:0,quantity:'',note:''}];transferNote.value='';uni.showModal({title:submit?'调拨单已提交':'调拨草稿已保存',content:submit?'调拨单已提交，等待后续审批处理。':'草稿已保存，可稍后继续提交。',showCancel:false});await refresh()}catch(e){message.value=error(e)}finally{acting.value=''}}
function chooseTransferRoute(e:{detail:{value:string|number}}){routeIndex.value=Number(e.detail.value);transferLines.value=[{itemIndex:0,quantity:'',note:''}]}
function addTransferLine(){transferLines.value.push({itemIndex:0,quantity:'',note:''})}function removeTransferLine(index:number){if(transferLines.value.length===1){message.value='调拨单至少保留一条物料。';return}transferLines.value.splice(index,1)}
async function transferAction(row:WarehouseTransfer,action:'approve'|'reject'|'ship'|'receive'|'cancel'){
  const allowed=action==='approve'||action==='reject'?canApproveTransfer.value:action==='ship'?canShipTransfer.value:action==='cancel'?canRequestTransfer.value:canReceiveTransfer.value
  if(!allowed)return
  if(action==='cancel'&&!await confirmAction('取消调拨单','取消后会释放已预占库存，是否继续？'))return
  if(action==='receive'){
    const lines=row.lines.filter(line=>Number(line.inTransitQuantity)>0).map(line=>({itemId:line.itemId,receivedQuantity:Number(receiveDrafts.value[transferLineKey(row.id,line.itemId)]||0)})).filter(line=>line.receivedQuantity>0)
    if(!lines.length||lines.some(line=>!Number.isFinite(line.receivedQuantity))||lines.some(line=>line.receivedQuantity>Number(row.lines.find(item=>item.itemId===line.itemId)?.inTransitQuantity||0))){message.value='请填写有效收货数量，且不能超过在途数量。';return}
    await work(row.id,()=>receiveMobileWarehouseTransfer(row.id,key('transfer-receive'),lines,'移动端按行确认调拨收货'))
    return
  }
  if(action==='approve'||action==='reject'){const note=await promptText(action==='approve'?'审批说明（可留空）':'驳回原因',action==='approve'?'移动端审批通过':'请填写驳回原因');if(action==='reject'&&!note)return;await work(row.id,()=>reviewMobileWarehouseTransfer(row.id,action==='approve',note||undefined));return}await work(row.id,()=>action==='ship'?shipMobileWarehouseTransfer(row.id,key('transfer-ship')):cancelMobileWarehouseTransfer(row.id,key('transfer-cancel'),'移动端取消调拨'))
}
async function configureAlert(item:{id:number;minStockQuantity?:number}){if(!canConfigure.value||!currentWarehouse.value)return;const value=await promptNumber('最低库存',String(item.minStockQuantity||0));if(value===null)return;await work(`alert-${item.id}`,()=>updateMobileWarehouseAlert(item.id,{warehouseId:currentWarehouse.value!.id,minStockQuantity:value,alertEnabled:true,expiryAlertDays:7}))}
async function createItem(){const category=selectedCategory.value,minimum=Number(newItemMinStock.value||0),price=Number(newItemPrice.value||0);if(!canConfigure.value||!category||!newItemCode.value.trim()||!newItemName.value.trim()||minimum<0||price<0){message.value='请填写物料编码、名称、类别、有效最低库存和采购单价。';return}acting.value='item-save';try{await saveMobileWarehouseItem({id:editingItemId.value,code:newItemCode.value.trim(),name:newItemName.value.trim(),categoryId:category.id,imageUrl:newItemImageUrl.value.trim()||undefined,unit:newItemUnit.value.trim()||undefined,purchaseUnit:newPurchaseUnit.value.trim()||undefined,stockUnit:newItemUnit.value.trim()||undefined,ingredientUnit:newIngredientUnit.value.trim()||undefined,unitConversionText:newConversion.value.trim()||undefined,spec:newItemSpec.value.trim()||undefined,warehouseLocation:newItemLocation.value.trim()||undefined,unitPrice:price,shelfLifeDays:optionalNumber(newShelfLife.value),minStockQuantity:minimum,alertEnabled:true,expiryAlertDays:optionalNumber(newExpiryAlertDays.value),itemAttributes:newItemAttributes.value.trim()||undefined,itemDescription:newItemDescription.value.trim()||undefined,active:true});resetItemForm();itemFormOpen.value=false;await refresh()}catch(e){message.value=error(e)}finally{acting.value=''}}
function editItem(item:WarehouseItem){editingItemId.value=item.id;newItemCode.value=item.code;newItemName.value=item.name;newItemUnit.value=item.stockUnit||item.unit||'';newPurchaseUnit.value=item.purchaseUnit||'';newIngredientUnit.value=item.ingredientUnit||'';newConversion.value=item.unitConversionText||'';newItemSpec.value=item.spec||'';newItemLocation.value=item.warehouseLocation||'';newItemMinStock.value=String(item.minStockQuantity||0);newItemPrice.value=String(item.unitPrice||0);newShelfLife.value=item.shelfLifeDays===undefined?'':String(item.shelfLifeDays);newExpiryAlertDays.value=item.expiryAlertDays===undefined?'':String(item.expiryAlertDays);newItemAttributes.value=item.itemAttributes||'';newItemDescription.value=item.itemDescription||'';newItemImageUrl.value=item.imageUrl||'';categoryIndex.value=Math.max(0,flatCategories.value.findIndex(row=>row.id===item.categoryId));tab.value='catalog'}
function resetItemForm(){editingItemId.value=undefined;newItemCode.value='';newItemName.value='';newItemUnit.value='';newPurchaseUnit.value='';newIngredientUnit.value='';newConversion.value='';newItemSpec.value='';newItemLocation.value='';newItemMinStock.value='';newItemPrice.value='';newShelfLife.value='';newExpiryAlertDays.value='';newItemAttributes.value='';newItemDescription.value='';newItemImageUrl.value=''}
async function receiveStock(){const warehouse=currentWarehouse.value,item=items.value[stockItemIndex.value],quantity=Number(stockQuantity.value),unitCost=Number(stockUnitCost.value);if(!canPurchase.value||!warehouse||!item||!stockBatchNo.value.trim()||!stockReceivedDate.value||quantity<=0||unitCost<0){message.value='请填写物料、批次号、到货日期、数量和成本。';return}await work('stock-receive',()=>receiveMobileWarehouseStock({warehouseId:warehouse.id,itemId:item.id,batchNo:stockBatchNo.value.trim(),receivedDate:stockReceivedDate.value,expiryDate:stockExpiryDate.value||undefined,quantity,unitCost,note:stockNote.value.trim()||undefined,clientRequestId:key('manual-receive')}));stockBatchNo.value='';stockExpiryDate.value='';stockQuantity.value='';stockUnitCost.value='';stockNote.value=''}
async function createCategory(){if(!canConfigure.value)return;const name=await promptText('新增物料类别','请输入类别名称');if(!name)return;await work('category-create',()=>saveMobileWarehouseItemCategory({name,enabled:true}))}
async function toggleItem(item:WarehouseItem){if(!canConfigure.value)return;const verb=item.active?'停用':'启用';if(!await confirmAction(`${verb}物料`,`${verb}后${item.name}将${item.active?'不能继续叫货或新增入库':'恢复使用'}，是否继续？`))return;await work(`item-${item.id}`,()=>setMobileWarehouseItemEnabled(item.id,!item.active))}
async function toggleCategory(category:WarehouseItemCategory){if(!canConfigure.value)return;const verb=category.enabled?'停用':'启用';if(!await confirmAction(`${verb}类别`,`${verb}类别“${category.name}”，是否继续？`))return;await work(`category-${category.id}`,()=>setMobileWarehouseItemCategoryEnabled(category.id,!category.enabled))}
async function removeCategory(category:WarehouseItemCategory){if(!canConfigure.value)return;if(!await confirmAction('删除物料类别',`删除“${category.name}”后无法恢复；仅无子级且未关联物料的类别可以删除。是否继续？`))return;await work(`category-delete-${category.id}`,()=>deleteMobileWarehouseItemCategory(category.id))}
function openItem(item:{id:number}){const warehouse=currentWarehouse.value;if(!warehouse)return;uni.navigateTo({url:`/pkg-warehouse/item-detail/index?itemId=${item.id}&warehouseId=${warehouse.id}`})}
async function openReceipt(batchId:number){try{await openProtectedFile({path:`/api/warehouse/print/receipts/${batchId}`,fileName:`采购入库单-${batchId}.pdf`,contentType:'application/pdf'})}catch(e){message.value=error(e)}}
async function openMovement(movementId:number){try{await openProtectedFile({path:`/api/warehouse/print/movements/${movementId}`,fileName:`库存流水单-${movementId}.pdf`,contentType:'application/pdf'})}catch(e){message.value=error(e)}}
async function work(id:string,fn:()=>Promise<unknown>,successTitle='操作成功',successContent='数据已保存。'){if(acting.value)return;acting.value=id;try{await fn();await refresh();uni.showModal({title:successTitle,content:successContent,showCancel:false})}catch(e){message.value=error(e)}finally{acting.value=''}}
function openPending(){uni.navigateTo({url:'/pkg-warehouse/index'})}function key(prefix:string){return`${prefix}-${Date.now()}-${Math.random().toString(36).slice(2,8)}`}function today(){return new Date().toISOString().slice(0,10)}function error(e:unknown){return e instanceof Error?e.message:'操作失败，请稍后重试。'}
function transferLineKey(transferId:string,itemId:number){return`${transferId}:${itemId}`}function confirmAction(title:string,content:string){return new Promise<boolean>(resolve=>uni.showModal({title,content,success:r=>resolve(r.confirm),fail:()=>resolve(false)}))}
function purchaseReceiveKey(orderId:string,itemId:number){return`${orderId}:${itemId}`}function purchaseDraft(orderId:string,itemId:number):{batchNo:string;receivedDate:string;expiryDate:string;note:string}{const draftKey=purchaseReceiveKey(orderId,itemId),existing=purchaseReceiveDrafts.value[draftKey];if(existing)return existing;const created={batchNo:`${today().replaceAll('-','')}-${itemId}`,receivedDate:today(),expiryDate:'',note:''};purchaseReceiveDrafts.value[draftKey]=created;return created}
function selectTab(value:typeof tabs[number]['k']){tab.value=value}
function setInventoryFilter(value:string){inventoryFilter.value=value as typeof inventoryFilter.value}
function setMovementDirection(value:string){movementDirection.value=value as typeof movementDirection.value}
function promptNumber(title:string,current:string){return new Promise<number|null>(resolve=>uni.showModal({title,editable:true,content:current,placeholderText:'请输入数量',success:r=>{if(!r.confirm){resolve(null);return}const n=Number(r.content);resolve(Number.isFinite(n)&&n>=0?n:null)},fail:()=>resolve(null)}))}
function promptText(title:string,placeholder:string){return new Promise<string|null>(resolve=>uni.showModal({title,editable:true,placeholderText:placeholder,success:r=>{const value=String(r.content||'').trim();resolve(r.confirm&&value?value:null)},fail:()=>resolve(null)}))}
function flattenCategories(rows:WarehouseItemCategory[],prefix=''):WarehouseItemCategory[]{return rows.flatMap(row=>[{...row,name:`${prefix}${row.name}`},...flattenCategories(row.children||[],`${prefix}— `)])}
function optionalNumber(value:string){return value.trim()===''?undefined:Number(value)}function quantity(value:number|undefined){if(value===undefined||value===null)return'—';const safe=Number(value);return Number.isInteger(safe)?String(safe):safe.toFixed(2)}
function riskLabel(level:string){return({OUT:'缺货',LOW:'低库存',EXPIRING:'临期',OVERSTOCK:'积压',OK:'正常'}as Record<string,string>)[level]||'待确认'}
</script>

<template><view class="page"><view class="head"><view><text class="eyebrow">仓库管理员</text><text class="title">仓库作业中心</text></view><button @click="openPending">待办</button></view>
<picker v-if="facilities.length" :range="facilities" range-key="name" @change="chooseWarehouse"><view class="warehouse-picker">{{currentWarehouse?.name||'选择仓库'}}<text>切换 ›</text></view></picker><view v-if="message" class="notice">{{message}}</view>
<scroll-view scroll-x class="tabs"><view class="tab-row"><button v-for="item in tabs" :key="item.k" :class="{active:tab===item.k}" @click="selectTab(item.k)">{{item.l}}</button></view></scroll-view>
<template v-if="tab==='purchase'"><view v-for="order in overview?.purchaseOrders||[]" :key="order.id" class="card"><view class="row"><text class="name">{{order.supplierName||'外部采购'}} · {{order.id}}</text><text>{{order.statusLabel||order.status}}</text></view><text class="copy">{{order.lines.length}} 种物料 · ¥{{Number(order.totalAmount||0).toFixed(2)}}</text><template v-if="canPurchase&&order.status==='ORDERED'"><view class="receive-tip">请逐项核对到货批次。当前接口要求一次确认全部已审批数量。</view><view v-for="line in order.lines" :key="line.itemId" class="receive-form"><text class="line-name">{{line.itemName}} · 应收 {{line.orderedQuantity}} {{line.unit||''}}</text><input v-model="purchaseDraft(order.id,line.itemId).batchNo" class="input" placeholder="到货批次号"/><picker mode="date" :value="purchaseDraft(order.id,line.itemId).receivedDate" @change="purchaseDraft(order.id,line.itemId).receivedDate=$event.detail.value"><view class="input">到货日期：{{purchaseDraft(order.id,line.itemId).receivedDate||'请选择'}}</view></picker><picker mode="date" :value="purchaseDraft(order.id,line.itemId).expiryDate" @change="purchaseDraft(order.id,line.itemId).expiryDate=$event.detail.value"><view class="input">到期日期：{{purchaseDraft(order.id,line.itemId).expiryDate||'未设置'}}</view></picker><input v-model="purchaseDraft(order.id,line.itemId).note" class="input" placeholder="本批备注（选填）"/></view></template><view class="actions"><button v-if="canPurchase&&order.status==='DRAFT'" @click="approvePurchase(order)">确认采购</button><button v-if="canPurchase&&order.status==='ORDERED'" :loading="acting===order.id" @click="receivePurchase(order)">核对并采购入库</button></view></view><view v-if="canPurchase&&!purchaseFormOpen" class="form"><button class="primary" @click="purchaseFormOpen=true">创建采购单</button></view><view v-else-if="canPurchase&&purchaseFormOpen" class="form"><view class="row"><text class="section">新建采购单</text><button class="plain" @click="purchaseFormOpen=false">取消</button></view><picker :range="suppliers" range-key="name" @change="supplierIndex=Number($event.detail.value)"><view class="input">{{suppliers[supplierIndex]?.name||'选择供应商'}}</view></picker><view v-for="(line,index) in purchaseLines" :key="index" class="receive-form"><view class="row"><text class="line-name">采购明细 {{index+1}}</text><button v-if="purchaseLines.length>1" class="danger" @click="removePurchaseLine(index)">移除</button></view><picker :range="items" range-key="name" @change="line.itemIndex=Number($event.detail.value)"><view class="input">{{items[line.itemIndex]?.name||'选择物料'}}</view></picker><input v-model="line.quantity" class="input" type="digit" placeholder="采购数量"/><input v-model="line.unitCost" class="input" type="digit" placeholder="采购单价"/></view><view class="actions"><button class="plain" @click="addPurchaseLine">增加物料</button><button class="primary" :loading="acting==='purchase-create'" @click="createPurchase">提交采购单</button></view></view></template>
<template v-else-if="tab==='transfer'"><view v-if="canRequestTransfer&&routes.length" class="form"><text class="section">新建调拨单</text><picker :range="routes.map(r=>`${r.sourceWarehouse.name} → ${r.targetWarehouse.name}`)" @change="routeIndex=Number($event.detail.value);transferLines=[{itemIndex:0,quantity:'',note:''}]"><view class="input">{{routes[routeIndex]?.sourceWarehouse.name}} → {{routes[routeIndex]?.targetWarehouse.name}}</view></picker><view v-for="(line,index) in transferLines" :key="index" class="receive-form"><view class="row"><text class="line-name">调拨明细 {{index+1}}</text><button v-if="transferLines.length>1" class="danger" @click="removeTransferLine(index)">移除</button></view><picker :range="routeMaterialLabels" @change="line.itemIndex=Number($event.detail.value)"><view class="input">{{routeMaterialLabels[line.itemIndex]||'选择物料'}}</view></picker><input v-model="line.quantity" class="input" type="digit" placeholder="调拨数量"/><input v-model="line.note" class="input" placeholder="本项说明（选填）"/></view><input v-model="transferNote" class="input" placeholder="调拨单说明（选填）"/><view class="actions"><button class="plain" @click="addTransferLine">增加物料</button><button class="plain" @click="createTransfer(false)">保存草稿</button><button class="primary" @click="createTransfer(true)">保存并提交</button></view></view><view v-if="canRequestTransfer&&!routes.length" class="card empty-state">当前账号没有可发起的调拨路线。请联系管理员配置目标分仓的数据范围后重新登录。</view><view v-for="row in transfers" :key="row.id" class="card"><view class="row"><text class="name">{{row.sourceWarehouseName}} → {{row.targetWarehouseName}}</text><text>{{row.statusLabel||row.status}}</text></view><text class="copy">{{row.transferNo||row.id}} · {{row.createdAt||'—'}}</text><text v-if="row.note" class="copy">说明：{{row.note}}</text><view v-for="line in row.lines" :key="line.itemId" class="detail-line"><view><text class="line-name">{{line.itemName}}</text><text class="copy">申请 {{line.requestedQuantity}} · 批准 {{line.approvedQuantity}} · 实发 {{line.shippedQuantity}} · 已收 {{line.receivedQuantity}} · 在途 {{line.inTransitQuantity}} {{line.unit||''}}</text></view><input v-if="canReceiveTransfer&&['SHIPPED','PARTIALLY_RECEIVED'].includes(row.status)&&Number(line.inTransitQuantity)>0" v-model="receiveDrafts[transferLineKey(row.id,line.itemId)]" class="receive-input" type="digit" :placeholder="String(line.inTransitQuantity)"/></view><text v-if="row.reviewNote" class="copy">审批说明：{{row.reviewNote}}</text><view class="actions"><button v-if="canRequestTransfer&&row.status==='DRAFT'" @click="work(row.id,()=>submitMobileWarehouseTransfer(row.id))">提交草稿</button><button v-if="canApproveTransfer&&row.status==='SUBMITTED'" @click="transferAction(row,'approve')">通过</button><button v-if="canApproveTransfer&&row.status==='SUBMITTED'" @click="transferAction(row,'reject')">驳回</button><button v-if="canShipTransfer&&row.status==='APPROVED'" @click="transferAction(row,'ship')">发出</button><button v-if="canReceiveTransfer&&['SHIPPED','PARTIALLY_RECEIVED'].includes(row.status)" @click="transferAction(row,'receive')">按填写数量接收</button><button v-if="canRequestTransfer&&['DRAFT','SUBMITTED','APPROVED'].includes(row.status)" class="danger" @click="transferAction(row,'cancel')">取消调拨</button></view></view></template>
<template v-else-if="tab==='inventory'"><view class="risk-grid"><view class="risk-summary danger"><text class="risk-number">{{inventoryCounts.risk}}</text><text>待处理风险</text></view><view class="risk-summary"><text class="risk-number">{{inventoryCounts.out+inventoryCounts.low}}</text><text>缺货/低库存</text></view><view class="risk-summary warning"><text class="risk-number">{{inventoryCounts.expiring}}</text><text>临期物料</text></view></view><scroll-view scroll-x class="filters"><view class="filter-row"><button v-for="filter in [{k:'RISK',l:`待处理 ${inventoryCounts.risk}`},{k:'OUT',l:`缺货 ${inventoryCounts.out}`},{k:'LOW',l:`低库存 ${inventoryCounts.low}`},{k:'EXPIRING',l:`临期 ${inventoryCounts.expiring}`},{k:'OVERSTOCK',l:`积压 ${inventoryCounts.overstock}`},{k:'OK',l:'正常'},{k:'ALL',l:'全部'}]" :key="filter.k" :class="{active:inventoryFilter===filter.k}" @click="setInventoryFilter(filter.k)">{{filter.l}}</button></view></scroll-view><view v-if="!inventoryItems.length" class="card empty-state">当前筛选条件下没有物料。</view><view v-for="item in inventoryItems" :key="item.id" class="card"><view class="row"><text class="name">{{item.name}}</text><text class="risk-chip" :class="`risk-${item.alertLevel.toLowerCase()}`">{{riskLabel(item.alertLevel)}}</text></view><text class="copy">{{item.alertText||item.stockStatus}}</text><view class="risk-detail"><view><text class="detail-label">仓库可用</text><text class="detail-value">{{quantity(item.warehouseAvailableQuantity)}} {{item.unit||''}}</text></view><view><text class="detail-label">最低库存</text><text class="detail-value">{{quantity(item.minStockQuantity)}} {{item.unit||''}}</text></view><view><text class="detail-label">可用天数</text><text class="detail-value">{{quantity(item.daysAvailable)}} 天</text></view></view><text class="copy">仓位 {{item.warehouseLocation||'未设置'}} · 最近到期 {{item.nearestExpiryDate||'暂无'}}</text><view class="actions"><button class="plain" @click="openItem(item)">查看批次与流水</button><button v-if="canConfigure" class="plain" @click="configureAlert(item)">设置预警</button></view></view></template>
<template v-else-if="tab==='movement'"><view class="form"><view class="row"><text class="section">出入库流水</text><text class="copy">{{filteredMovements.length}} 条</text></view><input v-model="movementKeyword" class="input" placeholder="搜索物料、批次或来源单号"/><scroll-view scroll-x class="filters"><view class="filter-row"><button v-for="item in [{k:'ALL',l:'全部'},{k:'IN',l:'入库'},{k:'OUT',l:'出库'}]" :key="item.k" :class="{active:movementDirection===item.k}" @click="setMovementDirection(item.k)">{{item.l}}</button></view></scroll-view><view class="date-row"><picker mode="date" :value="movementDateFrom" @change="movementDateFrom=$event.detail.value"><view class="date-input">开始：{{movementDateFrom||'不限'}}</view></picker><picker mode="date" :value="movementDateTo" @change="movementDateTo=$event.detail.value"><view class="date-input">结束：{{movementDateTo||'不限'}}</view></picker></view></view><view v-if="!filteredMovements.length" class="card empty-state">当前条件下没有库存流水。</view><view v-for="movement in filteredMovements" :key="movement.id" class="card"><view class="row"><text class="name">{{movement.itemName}} · {{movement.movementTypeLabel}}</text><text :class="{positive:movement.quantityDelta>0}">{{movement.quantityDelta>0?'+':''}}{{movement.quantityDelta}}</text></view><text class="copy">{{movement.warehouseName||movement.sourceWarehouseName||'仓库'}} · {{movement.operatorName||'系统'}} · {{movement.createdAt||'—'}}</text><text class="copy">来源：{{movement.sourceType||'—'}} {{movement.sourceId||''}} · 批次 {{movement.batchNo||'—'}}</text><button v-if="canReadFiles" class="plain" @click="openMovement(movement.id)">查看流水单</button></view><text class="section">采购入库单</text><view v-if="!(overview?.stockBatches||[]).length" class="card empty-state">暂无采购入库单。</view><view v-for="batch in overview?.stockBatches||[]" :key="batch.id" class="card"><text class="name">{{batch.itemName}} · {{batch.batchNo}}</text><text class="copy">入库 {{batch.quantity}} · {{batch.receivedDate}} · 到期 {{batch.expiryDate||'未设置'}}</text><button v-if="canReadFiles" class="plain" @click="openReceipt(batch.id)">查看入库单</button></view></template>
<template v-else><view class="form"><text class="section">物料档案怎么用</text><text class="copy">先按类别查看或新增物料；点击“查看详情”可维护编码、单位、仓位、预警和使用说明。</text><text class="copy">停用物料后不能继续叫货或新增入库，但历史单据和流水仍可查看。</text></view><text class="section">物料列表</text><view v-for="item in catalogItems" :key="item.id" class="card"><view class="row"><text class="name">{{item.name}}</text><text>{{item.active?'启用中':'已停用'}}</text></view><text class="copy">{{item.code}} · {{item.categoryName||item.category||'未分类'}} · {{item.spec||'无规格'}}</text><text class="copy">单位 {{item.unit||'—'}} · 仓位 {{item.warehouseLocation||'—'}}</text><view class="actions"><button class="plain" @click="openItem(item)">查看详情</button><button v-if="canConfigure" :class="item.active?'danger':'plain'" @click="toggleItem(item)">{{item.active?'停用':'启用'}}</button></view></view><view v-if="canConfigure&&!itemFormOpen" class="form"><button class="primary" @click="itemFormOpen=true">新增物料</button></view><view v-else-if="canConfigure&&itemFormOpen" class="form"><view class="row"><text class="section">新增物料</text><button class="plain" @click="itemFormOpen=false;resetItemForm()">取消</button></view><input v-model="newItemCode" class="input" placeholder="物料编码（如：TEA-001）"/><input v-model="newItemName" class="input" placeholder="物料名称"/><picker :range="categoryNames" @change="categoryIndex=Number($event.detail.value)"><view class="input">{{selectedCategory?.name||'选择物料类别'}}</view></picker><input v-model="newItemUnit" class="input" placeholder="库存单位（选填，如：包）"/><input v-model="newItemSpec" class="input" placeholder="规格（选填）"/><input v-model="newItemLocation" class="input" placeholder="仓位（选填）"/><input v-model="newItemMinStock" class="input" type="digit" placeholder="最低库存（未填按 0）"/><button class="primary" :loading="acting==='item-save'" @click="createItem">保存物料</button></view><view class="card"><view class="row"><text class="section">物料类别</text><button v-if="canConfigure" class="plain" @click="createCategory">新增类别</button></view><view v-for="category in flatCategories" :key="category.id" class="detail-line"><view><text class="line-name">{{category.name}}</text><text class="copy">{{category.enabled?'已启用':'已停用'}}</text></view><view v-if="canConfigure" class="actions"><button class="plain" @click="toggleCategory(category)">{{category.enabled?'停用':'启用'}}</button><button class="danger" @click="removeCategory(category)">删除</button></view></view><text v-if="!flatCategories.length" class="copy">暂无物料类别，请先新增类别。</text></view></template>
</view></template>

<style scoped lang="scss">.page{min-height:100vh;box-sizing:border-box;padding:24rpx;background:#f2f6f5;color:#202124}.head,.row,.actions,.warehouse-picker{display:flex;align-items:center;justify-content:space-between;gap:14rpx}.eyebrow,.title,.section,.name,.copy,.line-name{display:block}.eyebrow,.copy{color:#71807d;font-size:23rpx}.title{font-size:40rpx;font-weight:750}.warehouse-picker,.form,.card,.notice{margin-top:18rpx;padding:24rpx;background:#fff;border:1rpx solid #d9e6e3;border-radius:16rpx}.tabs,.filters{margin-top:18rpx;white-space:nowrap}.tab-row,.filter-row{display:inline-flex;gap:10rpx}.tab-row button,.filter-row button{margin:0;background:#fff;color:#59606b;font-size:24rpx}.tab-row button.active,.filter-row button.active,.primary{background:#27655f;color:#fff}.section,.name{font-size:29rpx;font-weight:700}.input{box-sizing:border-box;width:100%;margin-top:12rpx;padding:19rpx;background:#f7faf9;border-radius:12rpx}.copy{margin-top:10rpx}.actions{margin-top:14rpx;justify-content:flex-start;flex-wrap:wrap}.actions button,.plain{margin:0;background:#e6f3f1;color:#1f5752;font-size:24rpx}.actions .danger{background:#fff0ed;color:#963b30}.detail-line{display:flex;align-items:center;justify-content:space-between;gap:14rpx;margin-top:16rpx;padding-top:16rpx;border-top:1rpx solid #edf0f3}.line-name{font-size:26rpx;font-weight:650}.receive-input{box-sizing:border-box;width:170rpx;padding:15rpx;background:#f7faf9;border:1rpx solid #dfe3e8;border-radius:12rpx;text-align:right}.receive-tip{margin-top:16rpx;padding:16rpx;background:#fff7ed;color:#9a5b20;border-radius:10rpx;font-size:23rpx}.receive-form{margin-top:16rpx;padding-top:16rpx;border-top:1rpx solid #edf0f3}.date-row{display:grid;grid-template-columns:repeat(2,1fr);gap:12rpx;margin-top:12rpx}.date-input{padding:18rpx;background:#f7faf9;border-radius:12rpx;color:#59606b;font-size:23rpx}.risk-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12rpx;margin-top:18rpx}.risk-summary{padding:18rpx;background:#fff;border:1rpx solid #d9e6e3;border-radius:14rpx;color:#6a7079;font-size:22rpx}.risk-summary.danger{background:#fff0ed;color:#963b30}.risk-summary.warning{background:#fff8e8;color:#9a661b}.risk-number,.detail-label,.detail-value{display:block}.risk-number{font-size:34rpx;font-weight:750}.risk-detail{display:grid;grid-template-columns:repeat(3,1fr);gap:10rpx;margin-top:16rpx;padding-top:16rpx;border-top:1rpx solid #edf0f3}.detail-label{color:#71807d;font-size:22rpx}.detail-value{margin-top:5rpx;font-size:25rpx;font-weight:650}.risk-chip{padding:7rpx 12rpx;border-radius:10rpx;font-size:22rpx}.risk-out{background:#fff0ed;color:#963b30}.risk-low{background:#fff4e8;color:#a35a18}.risk-expiring{background:#fff8e8;color:#9a661b}.risk-overstock{background:#edf4ff;color:#396a9f}.risk-ok{background:#eaf5ed;color:#24663e}.empty-state{text-align:center;color:#71807d}.positive{color:#287a48}</style>
